import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyMinutes {
  day: string;
  minutes: number;
}

interface MeditationData {
  currentStreak: number;
  totalSessions: number;
  weeklyMinutes: WeeklyMinutes[];
}

export default function Widget() {
  const meditationData = response.data.data as MeditationData;
  const { currentStreak, totalSessions, weeklyMinutes } = meditationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#00BFA5' }}>
              Meditation Streak
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {currentStreak} Days
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Total Sessions: {totalSessions}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: weeklyMinutes.map(d => d.minutes),
                color: '#FFCA28',
              },
            ]}
            xAxis={[
              {
                data: weeklyMinutes.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
